let summaryChart = null;
function loadScript(src) {
  return new Promise((resolve, reject) => {
    if (document.querySelector(`script[src="${src}"]`)) {
      resolve();
      return;
    }
    const script = document.createElement("script");
    script.src = src;
    script.onload = resolve;
    script.onerror = reject;
    document.body.appendChild(script);
  });
}
function formatINR(val) {
  if (!isFinite(val)) return "N/A";
  return "₹ " + Math.round(val).toLocaleString("en-IN");
}
function getTaxDetails(income, regime) {
  if (income <= 0) {
    return { baseTax: 0, surcharge: 0, cess: 0, total: 0 };
  }
  let tax = 0;
  if (regime === "new") {
    if (income <= 400000) tax = 0;
    else if (income <= 800000) tax = (income - 400000) * 0.05;
    else if (income <= 1200000) tax = 20000 + (income - 800000) * 0.1;
    else if (income <= 1600000) tax = 60000 + (income - 1200000) * 0.15;
    else if (income <= 2000000) tax = 120000 + (income - 1600000) * 0.2;
    else if (income <= 2400000) tax = 200000 + (income - 2000000) * 0.25;
    else tax = 300000 + (income - 2400000) * 0.3;
    if (income <= 1200000) {
      tax = 0;
    } else {
      let excess = income - 1200000;
      if (tax > excess) tax = excess;
    }
    let surcharge = 0;
    if (income > 20000000) surcharge = tax * 0.25;
    else if (income > 10000000) surcharge = tax * 0.15;
    else if (income > 5000000) surcharge = tax * 0.1;
    let cess = (tax + surcharge) * 0.04;
    return { baseTax: tax, surcharge, cess, total: tax + surcharge + cess };
  }
  if (regime === "old") {
    if (income <= 250000) tax = 0;
    else if (income <= 500000) tax = (income - 250000) * 0.05;
    else if (income <= 1000000) tax = 12500 + (income - 500000) * 0.2;
    else tax = 112500 + (income - 1000000) * 0.3;
    if (income <= 500000) tax = 0;
    let surcharge = 0;
    if (income > 50000000) surcharge = tax * 0.37;
    else if (income > 20000000) surcharge = tax * 0.25;
    else if (income > 10000000) surcharge = tax * 0.15;
    else if (income > 5000000) surcharge = tax * 0.1;
    let cess = (tax + surcharge) * 0.04;
    return { baseTax: tax, surcharge, cess, total: tax + surcharge + cess };
  }
  return { baseTax: 0, surcharge: 0, cess: 0, total: 0 };
}
function toggleBreakdown() {
  const breakdown = document.getElementById("breakdown");
  breakdown.style.display =
    breakdown.style.display === "block" ? "none" : "block";
}
function updateChart(takeHome, taxesPaid, businessExpenses) {
  loadScript("https://cdn.jsdelivr.net/npm/chart.js")
    .then(() => {
      const ctx = document.getElementById("summaryChart").getContext("2d");
      if (summaryChart) summaryChart.destroy();
      summaryChart = new Chart(ctx, {
        type: "doughnut",
        data: {
          labels: ["Take-Home Pay", "Taxes Paid", "Business Expenses"],
          datasets: [
            {
              data: [takeHome, taxesPaid, businessExpenses],
              backgroundColor: ["#2563eb", "#ef4444", "#10b981"],
            },
          ],
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          layout: { padding: 10 },
          plugins: {
            legend: { position: "bottom" },
            tooltip: {
              callbacks: {
                label: (ctx) => `${ctx.label}:${formatINR(ctx.raw)}`,
              },
            },
          },
        },
      });
    })
    .catch((err) => {
      console.error("Failed to load Chart.js", err);
    });
}
function renderAdvanceSchedule(netPayable, chosenScenario, tdsCovered) {
  const table = document.getElementById("advanceSchedule");
  table.innerHTML = "";
  if (tdsCovered >= netPayable && netPayable <= 0) {
    table.innerHTML =
      "<tr><th>Note</th><td>TDS already covers your tax liability. No advance tax installment is required.</td></tr>";
    return;
  }
  if (netPayable <= 0) {
    table.innerHTML =
      "<tr><th>Note</th><td>Tax refund is expected. Advance tax is not due.</td></tr>";
    return;
  }
  if (chosenScenario.includes("44ADA")) {
    table.innerHTML = `<tr><th>Due Date</th><th>Installment</th><th>Amount</th></tr><tr><td>March 15</td><td>100%</td><td>${formatINR(netPayable)}</td></tr>`;
    return;
  }
  const installments = [
    { date: "June 15", percent: 15 },
    { date: "Sept 15", percent: 30 },
    { date: "Dec 15", percent: 30 },
    { date: "March 15", percent: 25 },
  ];
  let total = 0;
  table.innerHTML =
    "<tr><th>Due Date</th><th>Installment</th><th>Amount</th></tr>";
  installments.forEach((inst) => {
    const amount = Math.round((netPayable * inst.percent) / 100);
    total += amount;
    table.innerHTML += `<tr><td>${inst.date}</td><td>${inst.percent}%</td><td>${formatINR(amount)}</td></tr>`;
  });
  const diff = Math.round(netPayable - total);
  if (diff !== 0) {
    table.innerHTML += `<tr><td colspan="2"><strong>Adjustment</strong></td><td><strong>${formatINR(diff)}</strong></td></tr>`;
  }
}
function downloadReport() {
  loadScript(
    "https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.9.3/html2pdf.bundle.min.js",
  )
    .then(() => {
      const element = document.getElementById("report");
      html2pdf().from(element).save("freelancer-tax-report.pdf");
    })
    .catch((err) => {
      console.error("Failed to load html2pdf.js", err);
    });
}
function calculateTaxes() {
  const grossReceipts =
    parseFloat(document.getElementById("grossReceipts").value) || 0;
  const cashReceipts =
    parseFloat(document.getElementById("cashReceipts").value) || 0;
  const exportIncome =
    parseFloat(document.getElementById("exportIncome").value) || 0;
  const expenses = parseFloat(document.getElementById("expenses").value) || 0;
  const interestIncome =
    parseFloat(document.getElementById("interestIncome").value) || 0;
  const rentalIncome =
    parseFloat(document.getElementById("rentalIncome").value) || 0;
  const deduction80C =
    parseFloat(document.getElementById("deduction80C").value) || 0;
  const deduction80CCD =
    parseFloat(document.getElementById("deduction80CCD").value) || 0;
  const deduction80D =
    parseFloat(document.getElementById("deduction80D").value) || 0;
  const homeLoanInterest =
    parseFloat(document.getElementById("homeLoanInterest").value) || 0;
  const tdsDeducted =
    parseFloat(document.getElementById("tdsDeducted").value) || 0;
  const cashPercent =
    grossReceipts > 0 ? (cashReceipts / grossReceipts) * 100 : 0;
  const limit44ADA = cashPercent <= 5 ? 7500000 : 5000000;
  const is44ADAEligible = grossReceipts <= limit44ADA;
  const totalOtherIncome = interestIncome + rentalIncome;
  const totalDeductions =
    Math.min(deduction80C, 150000) +
    Math.min(deduction80CCD, 50000) +
    Math.min(deduction80D, 50000) +
    Math.min(homeLoanInterest, 200000);
  const domesticReceipts = Math.max(0, grossReceipts - exportIncome);
  const totalIncome = grossReceipts + totalOtherIncome;
  const incRegNew = Math.max(0, grossReceipts - expenses + totalOtherIncome);
  const taxRegNewDetails = getTaxDetails(incRegNew, "new");
  const incRegOld = Math.max(
    0,
    grossReceipts - expenses - totalDeductions + totalOtherIncome,
  );
  const taxRegOldDetails = getTaxDetails(incRegOld, "old");
  let inc44ADANew = 0;
  let tax44ADANewDetails = { total: Infinity };
  let inc44ADAOld = 0;
  let tax44ADAOldDetails = { total: Infinity };
  if (is44ADAEligible) {
    inc44ADANew = Math.max(0, grossReceipts * 0.5 + totalOtherIncome);
    tax44ADANewDetails = getTaxDetails(inc44ADANew, "new");
    inc44ADAOld = Math.max(
      0,
      grossReceipts * 0.5 - totalDeductions + totalOtherIncome,
    );
    tax44ADAOldDetails = getTaxDetails(inc44ADAOld, "old");
  }
  document.getElementById("inc-new-44ada").innerText = is44ADAEligible
    ? formatINR(inc44ADANew)
    : "N/A";
  document.getElementById("tax-new-44ada").innerText = is44ADAEligible
    ? formatINR(tax44ADANewDetails.total)
    : "Limit Exceeded";
  document.getElementById("inc-old-44ada").innerText = is44ADAEligible
    ? formatINR(inc44ADAOld)
    : "N/A";
  document.getElementById("tax-old-44ada").innerText = is44ADAEligible
    ? formatINR(tax44ADAOldDetails.total)
    : "Limit Exceeded";
  document.getElementById("inc-new-reg").innerText = formatINR(incRegNew);
  document.getElementById("tax-new-reg").innerText = formatINR(
    taxRegNewDetails.total,
  );
  document.getElementById("inc-old-reg").innerText = formatINR(incRegOld);
  document.getElementById("tax-old-reg").innerText = formatINR(
    taxRegOldDetails.total,
  );
  const validDetails = [
    { name: "Regular + New Regime", details: taxRegNewDetails },
    { name: "Regular + Old Regime", details: taxRegOldDetails },
  ];
  if (is44ADAEligible) {
    validDetails.push(
      { name: "44ADA + New Regime", details: tax44ADANewDetails },
      { name: "44ADA + Old Regime", details: tax44ADAOldDetails },
    );
  }
  const best = validDetails.reduce((bestSoFar, candidate) =>
    candidate.details.total < bestSoFar.details.total ? candidate : bestSoFar,
  );
  document
    .querySelectorAll(".card")
    .forEach((c) => c.classList.remove("highlight"));
  const cardMap = {
    "44ADA + New Regime": "card-new-44ada",
    "44ADA + Old Regime": "card-old-44ada",
    "Regular + New Regime": "card-new-reg",
    "Regular + Old Regime": "card-old-reg",
  };
  document.getElementById(cardMap[best.name]).classList.add("highlight");
  const netTaxPayable = Math.max(0, best.details.total - tdsDeducted);
  const taxRefund = Math.max(0, tdsDeducted - best.details.total);
  document.getElementById("net-tax").innerText = formatINR(netTaxPayable);
  document.getElementById("tax-refund").innerText = formatINR(taxRefund);
  const recommendation = best.name.includes("44ADA")
    ? "ITR-4 (Sugam) is recommended if eligible for Section 44ADA."
    : "ITR-3 is recommended; maintain Balance Sheet/P&L for Regular Method.";
  document.getElementById("itr-recommendation").innerText = recommendation;
  document.getElementById("breakdownScenario").innerText = best.name;
  document.getElementById("breakdownBaseTax").innerText = formatINR(
    best.details.baseTax,
  );
  document.getElementById("breakdownSurcharge").innerText = formatINR(
    best.details.surcharge,
  );
  document.getElementById("breakdownCess").innerText = formatINR(
    best.details.cess,
  );
  document.getElementById("breakdownTotalTax").innerText = formatINR(
    best.details.total,
  );
  const takeHome = Math.max(0, totalIncome - expenses - best.details.total);
  updateChart(takeHome, best.details.total, expenses);
  renderAdvanceSchedule(netTaxPayable, best.name, tdsDeducted);
  const alertBanner = document.getElementById("alertBanner");
  if (grossReceipts > 2000000) {
    alertBanner.style.display = "block";
    alertBanner.innerHTML = `⚠️ Your gross receipts exceed ₹20,00,000.GST registration is likely mandatory for domestic services.Domestic receipts:${formatINR(domesticReceipts)},Export receipts:${formatINR(exportIncome)}.`;
  } else {
    alertBanner.style.display = "none";
  }
  document.getElementById("results").style.display = "block";
}
